import React from 'react';

const Navbar = () => (
  <nav
    className="fixed w-full flex gap-6 p-4"
    style={{
      background: '#0d6efd',
      fontFamily: "'Orbitron', sans-serif",
    }}
  >
    {['Home','About-Me','Education','Experience','Skills','Projects','Contact'].map(link => (
      <a key={link} href={`#${link}`} style={{ color: '#fff' }}>
        {link}
      </a>
    ))}
  </nav>
);

export default Navbar;
